"use client";
import { useState } from "react";
import { motion, useReducedMotion } from "framer-motion";
const phases=["Brief","Design","Build","Review"];
export default function CompassStepRail(){const [active,setActive]=useState(0);const reduced=useReducedMotion();const move=(next:number)=>setActive((next+phases.length)%phases.length);return <section className="w-full max-w-md rounded-[22px] border border-[#ececee] bg-white p-5 shadow-sm"><div role="tablist" aria-label="Project phases" className="relative flex justify-between gap-1">{phases.map((phase,index)=><button key={phase} role="tab" aria-selected={active===index} aria-controls="compass-panel" onClick={()=>setActive(index)} onKeyDown={e=>{if(e.key==="ArrowRight")move(active+1);if(e.key==="ArrowLeft")move(active-1);if(e.key==="Home")setActive(0);if(e.key==="End")setActive(3)}} className="relative z-10 min-h-11 flex-1 rounded-xl px-2 text-xs font-black text-[#111] focus-visible:outline focus-visible:outline-2 focus-visible:outline-offset-2"><span className="block text-[#4a4a4f]">0{index+1}</span>{phase}{active===index&&<motion.span layoutId="compass-marker" transition={reduced?{duration:.12}:{type:"spring",stiffness:350,damping:28}} className="absolute inset-x-1 -bottom-1 h-1 rounded-full bg-[#53e8d4]"/>}</button>)}</div><motion.div id="compass-panel" role="tabpanel" key={active} initial={{opacity:0,y:reduced?0:5}} animate={{opacity:1,y:0}} transition={{duration:.18}} className="mt-5 rounded-2xl bg-[#f4f5f6] p-4"><b>{phases[active]} phase</b><p aria-live="polite" className="mt-1 text-sm text-[#4a4a4f]">Phase {active+1} of 4 is selected.</p></motion.div></section>}
